<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\{DailyReport,DailyReportItem,MissingDailyReport,Task,TaskApproval,WorkProof};
class ManagerDashboardController extends Controller{use Concerns;public function __invoke(){ $this->requirePerm('tenant.daily_reports.review');return view('tenant.manager-dashboard',['todaySubmittedReports'=>DailyReport::whereDate('report_date',today())->where('status','submitted')->count(),'missingReports'=>MissingDailyReport::where('status','missing')->count(),'lateReports'=>DailyReport::where('is_late',true)->count(),'pendingApprovals'=>TaskApproval::where('status','pending')->count(),'proofPending'=>WorkProof::where('status','submitted')->count(),'staffBlockers'=>DailyReportItem::where('item_type','blocker')->count(),'overdueTasks'=>Task::whereDate('due_date','<',today())->where('status','!=','completed')->count(),'followUpRequired'=>0]);}}
